import React, { useState } from "react";

function SOP() {
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const runModule1 = async () => {
    setLoading(true);

    try {
      const res = await fetch("http://localhost:5000/module1");
      const data = await res.json();
      setResult(data);
    } catch (error) {
      console.error(error);
      alert("Backend error");
    }

    setLoading(false);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "20px" }}>

      <button onClick={runModule1}>Run Module 1</button>

      {loading && <p>Processing...</p>}

      {result && result.status === "success" && (
        <div>

          <h3>Output</h3>
          <p><b>NPSV Length:</b> {result.npsv_length}</p>
          <p><b>Segments Shape:</b> {result.segments_shape.join(", ")}</p>

          {/* 🔹 TABLE */}
          <h3>NPSV Values</h3>

          <div style={{ maxHeight: "300px", overflowY: "scroll", border: "1px solid gray" }}>
            <table border="1" style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr>
                  <th>Index</th>
                  <th>NPSV Value</th>
                </tr>
              </thead>

              <tbody>
                {result.sample_npsv.map((value, index) => (
                  <tr key={index}>
                    <td>{index}</td>
                    <td>{value.toFixed(5)}</td>
                  </tr>
                ))}
              </tbody>

            </table>
          </div>

        </div>
      )}

    </div>
  );
}

export default SOP;
